    /// <summary>
    /// Extension of the <c>init</c> method for the ETGSPAIN model.
    /// </summary>
    /// <remarks>This code is used to show/hide features in Spanish companies.</remarks>
    public void init()
    {
        next init();
        NoYesId currentCompanyIsSpanishCompany  = CurrentCompanyIsSpanishCompany();

        this.design().controlName(formControlStr(EcoResProductDetailsExtended,ETGSPAIN_InventTable_ETGSPAINItemTextPrintoutOfAgreements)).visible(currentCompanyIsSpanishCompany);
        this.design().controlName(formControlStr(EcoResProductDetailsExtended,ETGSPAINExtraFields)).visible(currentCompanyIsSpanishCompany);        
	}
